  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared';
  3	import { GraphEmpty } from '@odf/shared/charts';
  4	import { TWENTY_FOUR_HOURS } from '@odf/shared/constants/common';
  5	import { DataUnavailableError } from '@odf/shared/generic/Error';
  6	import {
  7	  useCustomPrometheusPoll,
  8	  usePrometheusBasePath,
  9	} from '@odf/shared/hooks/custom-prometheus-poll';
 10	import useRefWidth from '@odf/shared/hooks/ref-width';
 11	import { humanizePercentage } from '@odf/shared/utils/humanize';
 12	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 13	import {
 14	  Chart,
 15	  ChartAxis,
 16	  ChartGroup,
 17	  ChartLegend,
 18	  ChartLine,
 19	  ChartVoronoiContainer,
 20	} from '@patternfly/react-charts';
 21	import { t_global_color_brand_default as activeColor } from '@patternfly/react-tokens';
 22	import { HEALTH_SCORE_QUERY } from '../odf-dashboard/queries';
 23	import { AlertRowData } from './hooks';
 24	import { getSeverityColor } from './utils';
 25	import './infra-health-graph.scss';
 26	
 27	type InfraHealthGraphProps = {
 28	  alerts?: AlertRowData[];
 29	  alertsLoaded?: boolean;
 30	  alertsError?: unknown;
 31	};
 32	
 33	const getScoreSeries = (
 34	  response: PrometheusResponse | null
 35	): { x: Date; y: number }[] => {
 36	  const values = response?.data?.result?.[0]?.values ?? [];
 37	
 38	  return values.map(([timestamp, value]: [number, string]) => ({
 39	    x: new Date(timestamp * 1000),
 40	    y: Number(value),
 41	  }));
 42	};
 43	
 44	const getAlertSeries = (alerts: AlertRowData[]) => {
 45	  if (!alerts.length) {
 46	    return [];
 47	  }
 48	
 49	  const MIN_Y = 10;
 50	  const MAX_Y = 100;
 51	  const bandHeight = MAX_Y - MIN_Y;
 52	  const laneCount = alerts.length;
 53	  const gap = bandHeight / (laneCount + 1);
 54	
 55	  const now = new Date();
 56	  const twentyFourHoursAgo = new Date(now.getTime() - TWENTY_FOUR_HOURS);
 57	
 58	  return alerts.map((alert, index) => {
 59	    const laneY = MIN_Y + gap * (index + 1);
 60	
 61	    // Clamp start time to the 24-hour window
 62	    const start = new Date(
 63	      Math.max(alert.startTime.getTime(), twentyFourHoursAgo.getTime())
 64	    );
 65	    // Clamp end time to now
 66	    const end = alert.endTime
 67	      ? new Date(Math.min(alert.endTime.getTime(), now.getTime()))
 68	      : now;
 69	
 70	    return {
 71	      alert,
 72	      data: [
 73	        { x: start, y: laneY },
 74	        { x: end, y: laneY },
 75	      ],
 76	    };
 77	  });
 78	};
 79	
 80	export const InfraHealthGraph: React.FC<InfraHealthGraphProps> = ({
 81	  alerts = [],
 82	  alertsLoaded = true,
 83	  alertsError = null,
 84	}) => {
 85	  const { t } = useCustomTranslation();
 86	
 87	  const [ref, width] = useRefWidth();
 88	  const [scoreResponse, scoreError, scoreLoading] = useCustomPrometheusPoll({
 89	    query: HEALTH_SCORE_QUERY,
 90	    endpoint: 'api/v1/query_range' as any,
 91	    timespan: TWENTY_FOUR_HOURS,
 92	    basePath: usePrometheusBasePath(),
 93	  });
 94	
 95	  const scoreSeries = React.useMemo(
 96	    () => getScoreSeries(scoreResponse),
 97	    [scoreResponse]
 98	  );
 99	
100	  const alertSeries = React.useMemo(() => getAlertSeries(alerts), [alerts]);
101	
102	  const scoreHasData = scoreSeries?.length > 0;
103	  const alertsHaveData = alertSeries?.length > 0;
104	
105	  const scoreLoadingOnly = scoreLoading && !scoreResponse && !scoreHasData;
106	  const alertsLoadingOnly = !alertsLoaded && !alertsError && !alertsHaveData;
107	
108	  const scoreFailed = !!scoreError && !scoreHasData;
109	  const alertsFailed = !!alertsError && !alertsHaveData;
110	
111	  const isLoading = scoreLoadingOnly && alertsLoadingOnly;
112	  const hasError = scoreFailed && alertsFailed;
113	
114	  let content: React.ReactNode;
115	
116	  if (isLoading) {
117	    content = <GraphEmpty height={250} loading />;
118	  } else if (hasError) {
119	    content = <DataUnavailableError />;
120	  } else if (!scoreHasData && !alertsHaveData) {
121	    content = <GraphEmpty height={250} loading={false} />;
122	  } else {
123	    const now = new Date();
124	    const twentyFourHoursAgo = new Date(now.getTime() - TWENTY_FOUR_HOURS);
125	
126	    content = (
127	      <Chart
128	        height={250}
129	        width={width}
130	        scale={{ x: 'time', y: 'linear' }}
131	        padding={{ top: 20, bottom: 60, left: 70, right: 80 }}
132	        domain={{
133	          x: [twentyFourHoursAgo, now],
134	          y: [0, 100],
135	        }}
136	        legendData={[
137	          {
138	            name: t('Health score'),
139	            symbol: { type: 'line', fill: activeColor.value },
140	          },
141	          {
142	            name: t('Critical'),
143	            symbol: { type: 'minus', fill: getSeverityColor('critical') },
144	          },
145	          {
146	            name: t('Moderate'),
147	            symbol: { type: 'minus', fill: getSeverityColor('warning') },
148	          },
149	          {
150	            name: t('Minor'),
151	            symbol: { type: 'minus', fill: getSeverityColor('info') },
152	          },
153	        ]}
154	        legendPosition="bottom"
155	        legendAllowWrap={true}
156	        legendComponent={
157	          <ChartLegend
158	            style={{
159	              labels: { fill: 'var(--pf-t--global--text--color--regular)' },
160	            }}
161	          />
162	        }
163	        containerComponent={
164	          <ChartVoronoiContainer
165	            voronoiDimension="x"
166	            constrainToVisibleArea
167	            labels={({ datum }) => {
168	              if (datum.type === 'score') {
169	                return `${humanizePercentage(datum.y).string} ${t('at')} ${datum.x.toLocaleTimeString()}`;
170	              }
171	
172	              const start = new Date(datum.startTime).toLocaleString();
173	              const end = new Date(datum.endTime).toLocaleString();
174	              return t(
175	                'Alert: {{name}} ({{severity}})\nStart: {{start}}\nEnd: {{end}}',
176	                {
177	                  name: datum.alertname,
178	                  severity: datum.severity,
179	                  start,
180	                  end,
181	                }
182	              );
183	            }}
184	          />
185	        }
186	      >
187	        <ChartAxis
188	          style={{
189	            tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
190	          }}
191	        />
192	        <ChartAxis
193	          dependentAxis
194	          tickFormat={(v) => `${v}%`}
195	          style={{
196	            tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
197	          }}
198	        />
199	        <ChartGroup>
200	          {scoreHasData && (
201	            <ChartLine
202	              data={scoreSeries.map((point) => ({
203	                ...point,
204	                type: 'score',
205	              }))}
206	              style={{
207	                data: {
208	                  strokeDasharray: '3,3',
209	                  stroke: activeColor.value,
210	                },
211	              }}
212	            />
213	          )}
214	          {alertSeries.map(({ alert, data }) => (
215	            <ChartLine
216	              key={alert.metadata.uid}
217	              data={data.map((point) => ({
218	                ...point,
219	                type: 'alert',
220	                alertname: alert.alertname,
221	                severity: alert.severity,
222	                startTime: alert.startTime,
223	                endTime: alert.endTime ?? new Date(),
224	              }))}
225	              style={{
226	                data: {
227	                  strokeWidth: 6,
228	                  stroke: getSeverityColor(alert.severity),
229	                },
230	              }}
231	            />
232	          ))}
233	        </ChartGroup>
234	      </Chart>
235	    );
236	  }
237	
238	  return (
239	    <div ref={ref} className="pf-v6-u-mt-sm odf-infra-health-graph">
240	      {content}
241	    </div>
242	  );
243	};
244	
245	export default InfraHealthGraph;

